/**
 * @param {string | number} l 
 * @param {string | number} r 
 * @param {string} directions 
 * @returns {number}
 */
function solve(l, r, directions) {
    // Use BigInt for safe handling of L and R up to 9 * 10^15
    const bigL = BigInt(l);
    const bigR = BigInt(r);

    // --- Helper 1: Pad to 16 digits string ---
    const padTo16 = (n) => {
        if (typeof n === 'bigint') {
            n = n.toString();
        } else {
            n = n.toString();
        }
        return n.padStart(16, '0');
    };

    // --- Step 1: Calculate Path Indices P_k ---
    const R_GRID = 4;
    const C_GRID = 4;
    const P = [];

    let r_curr = 0;
    let c_curr = 0;

    // P[0] corresponds to (0, 0)
    P.push(r_curr * C_GRID + c_curr); 

    for (let k = 0; k < 6; k++) {
        if (directions[k] === 'D') {
            r_curr += 1;
        } else { // 'R'
            c_curr += 1;
        }

        // Assuming path stays within bounds [0, 3] as suggested by examples
        // If bounds violation occurred, we assume clamping or an implicit constraint handles it.
        r_curr = Math.min(r_curr, R_GRID - 1);
        c_curr = Math.min(c_curr, C_GRID - 1);

        P.push(r_curr * C_GRID + c_curr);
    }

    // --- Helper 2: Digit DP Function ---
    // Counts numbers X <= N_str such that D[P_k] = V[k] for all k=0..6
    const count_le = (N_str, V) => {
        const N_digits = N_str.split('').map(d => parseInt(d));
        const M = N_digits.length; // M = 16

        // Memoization table: dp[i][tight]
        // Since V is fixed, we don't need V in the state key.
        const memo = new Array(M + 1).fill(0).map(() => new Array(2).fill(-1));

        /**
         * @param {number} i Current digit index (0 to 15)
         * @param {number} tight Tight constraint flag (1 if restricted by N_str)
         * @returns {bigint} Count of valid suffixes
         */
        const dp = (i, tight) => {
            if (i === M) {
                return 1n; // Found one valid number
            }
            if (memo[i][tight] !== -1) {
                return memo[i][tight];
            }

            let count = 0n;
            const limit = tight ? N_digits[i] : 9;

            for (let d = 0; d <= limit; d++) {
                // Check constraint: If i is a path index P_k, d must match V[k].
                let constraint_ok = true;

                for (let k = 0; k < 7; k++) {
                    if (P[k] === i) {
                        if (d !== V[k]) {
                            constraint_ok = false;
                            break;
                        }
                    }
                }

                if (constraint_ok) {
                    const new_tight = tight && (d === limit) ? 1 : 0;
                    count += dp(i + 1, new_tight);
                }
            }

            memo[i][tight] = count;
            return count;
        };

        // Start DP from index 0, tight constraint active (1)
        return dp(0, 1);
    };

    // --- Step 2: Generate Valid Sequences V (v0 <= v1 <= ... <= v6) ---
    const valid_V_sequences = [];

    /**
     * Generates all non-decreasing sequences V of length 7, values 0-9.
     * @param {number} k Current index in V (0 to 6)
     * @param {number} min_val Minimum allowed value for V[k]
     * @param {number[]} current_V Sequence built so far
     */
    const generateSequences = (k, min_val, current_V) => {
        if (k === 7) {
            valid_V_sequences.push([...current_V]);
            return;
        }

        for (let v = min_val; v <= 9; v++) {
            current_V.push(v);
            generateSequences(k + 1, v, current_V);
            current_V.pop();
        }
    };

    generateSequences(0, 0, []);

    // --- Step 3 & 4: Sum up differences ---
    let total_good_numbers = 0n;

    // Calculate L-1
    let bigL_minus_1 = bigL - 1n;

    for (const V of valid_V_sequences) {
        // Count for R
        const R_str = padTo16(bigR);
        const countR = count_le(R_str, V);

        // Count for L-1
        let countL_minus_1 = 0n;
        if (bigL_minus_1 >= 0n) {
            const L_minus_1_str = padTo16(bigL_minus_1);
            countL_minus_1 = count_le(L_minus_1_str, V);
        }

        const contribution = countR - countL_minus_1;
        total_good_numbers += contribution;
    }

    // The result must be returned as a standard number if possible, but since we used BigInt, 
    // we convert back if it fits standard JS number range, or return it as BigInt equivalent if required by strict signature adherence.
    // Assuming the final count fits within standard JS safe integer range if inputs are reasonable, though it could potentially exceed 2^53.
    // Given the constraints, the count is at most R, so it might exceed safe integer limit. Returning standard Number might cause precision loss.
    // We return the result coerced to Number based on typical contest expectations, but acknowledge potential loss if the count > 2^53 - 1.
    return Number(total_good_numbers);
