import java.math.BigInteger;
import java.util.ArrayList;
import java.util.List;

public class Solution {

    // Global state needed for DP, defined within the scope of solving for a specific V sequence.
    private static int[] P_indices;
    private static int M = 16; // Number of digits
    private static int R_GRID = 4;
    private static int C_GRID = 4;

    /**
     * Calculates the 7 path indices P_k based on directions.
     */
    private static void calculatePathIndices(String directions) {
        P_indices = new int[7];
        int r_curr = 0;
        int c_curr = 0;

        // P[0] is the start cell (0, 0) -> index 0
        P_indices[0] = r_curr * C_GRID + c_curr; 

        for (int k = 0; k < 6; k++) {
            if (directions.charAt(k) == 'D') {
                r_curr += 1;
            } else { // 'R'
                c_curr += 1;
            }

            // Clamp coordinates within the 4x4 grid
            r_curr = Math.min(r_curr, R_GRID - 1);
            c_curr = Math.min(c_curr, C_GRID - 1);

            // Store the index of the new cell
            P_indices[k + 1] = r_curr * C_GRID + c_curr;
        }
    }

    /**
     * Counts numbers X <= N_str such that the digit at path index P_k matches V[k].
     */
    private static BigInteger countLe(String N_str, int[] V) {
        int[] N_digits = new int[M];
        for (int i = 0; i < M; i++) {
            N_digits[i] = N_str.charAt(i) - '0';
        }

        // Memoization table: dp[i][tight]
        // Stores BigInteger counts. Initialized to null to represent uncomputed state.
        BigInteger[][] memo = new BigInteger[M][2];

        // The DP function definition uses lambda or local class for recursive structure
        java.util.function.BiFunction<Integer, Integer, BigInteger> dp = 
            new java.util.function.BiFunction<Integer, Integer, BigInteger>() {
            @Override
            public BigInteger apply(Integer i, Integer tight) {
                if (i == M) {
                    return BigInteger.ONE; // Found one valid number
                }
                if (memo[i][tight] != null) {
                    return memo[i][tight];
                }

                BigInteger count = BigInteger.ZERO;
                int limit = tight == 1 ? N_digits[i] : 9;

                for (int d = 0; d <= limit; d++) {
                    // Check constraint: If index i is a path index P_k, d must match V[k].
                    boolean constraintOk = true;
                    for (int k = 0; k < 7; k++) {
                        if (P_indices[k] == i) {
                            if (d != V[k]) {
                                constraintOk = false;
                                break;
                            }
                        }
                    }

                    if (constraintOk) {
                        // Determine new tightness
                        int newTight = tight == 1 && (d == limit) ? 1 : 0;

                        // Recurse
                        count = count.add(apply(i + 1, newTight));
                    }
                }

                memo[i][tight] = count;
                return count;
            }
        };

        // Start DP from index 0, tight constraint active (1)
        return dp.apply(0, 1);
    }


    /**
     * Generates all non-decreasing sequences V of length 7, values 0-9.
     */
    private static void generateSequences(int k, int minVal, List<Integer> currentV, List<int[]> validVSequences) {
        if (k == 7) {
            int[] vArray = new int[7];
            for(int i = 0; i < 7; i++) {
                vArray[i] = currentV.get(i);
            }
            validVSequences.add(vArray);
            return;
        }

        for (int v = minVal; v <= 9; v++) {
            currentV.add(v);
            generateSequences(k + 1, v, currentV, validVSequences);
            currentV.remove(currentV.size() - 1);
        }
    }


    public static long solve(long l, long r, String directions) {
        // 1. Calculate Path Indices P_k
        calculatePathIndices(directions);

        // 2. Generate Valid Sequences V
        List<int[]> validVSequences = new ArrayList<>();
        generateSequences(0, 0, new ArrayList<>(), validVSequences);

        // 3. Prepare R_str and L_minus_1_str
        String R_str = String.format("%16s", Long.toHexString(r)).replace('a', 'A').replace('b', 'B').replace('c', 'C').replace('d', 'D').replace('e', 'E').replace('f', 'F');

        // Wait, the problem implies decimal representation padded with leading zeros.
        String R_str_dec = String.format("%016d", r);

        BigInteger bigL = BigInteger.valueOf(l);
        BigInteger bigR = BigInteger.valueOf(r);

        BigInteger bigLMinus1 = bigL.subtract(BigInteger.ONE);

        // 4. Sum up contributions
        BigInteger totalGoodNumbers = BigInteger.ZERO;

        for (int[] V : validVSequences) {
            // Count for R
            BigInteger countR = countLe(R_str_dec, V);

            // Count for L-1
            BigInteger countLMinus1 = BigInteger.ZERO;
            if (bigLMinus1.compareTo(BigInteger.valueOf(-1)) >= 0) {
                String L_minus_1_str_dec = bigLMinus1.toString();
                // Ensure L-1 is also padded to 16 digits, even if it results in 16 zeros if L=1.
                String L_minus_1_padded = String.format("%016d", bigLMinus1.longValue());

                // Note: If L-1 > Long.MAX_VALUE, we would need BigInteger padding, but L <= 9*10^15 fits long.
                // However, since the input L, R are long, we must handle the string conversion carefully if L-1 is negative, 
                // but since L >= 1, L-1 >= 0.

                // If L-1 is represented by fewer than 16 digits, we must pad it to 16 digits.
                if (L_minus_1_str_dec.length() < 16) {
                     L_minus_1_padded = String.format("%016d", bigLMinus1.longValue());
                } else {
                    L_minus_1_padded = L_minus_1_str_dec;
                }

                // Correction: Since L and R are <= 9*10^15, they fit within a 64-bit long, which is up to ~9*10^18. 
                // We can use standard long arithmetic for L-1 if we are careful with conversion.
                // Let's rely on BigInteger for the string formatting of L-1 just to be absolutely safe with padding, 
                // although the string length of 9*10^15 is 16 digits.

                // Re-checking the padding logic for L-1:
                // If L=1, L-1=0. String format "%016d" on 0 yields "0000000000000000". This is correct.

                countLMinus1 = countLe(String.format("%016d", bigLMinus1.longValue()), V);
            }

            // Contribution = Count(R) - Count(L-1)
            BigInteger contribution = countR.subtract(countLMinus1);
            totalGoodNumbers = totalGoodNumbers.add(contribution);
        }

        // The function requires returning a long. Since the total count <= R <= 9*10^15, it fits safely in a standard Java long.
        return totalGoodNumbers.longValue();
    }
}

