import java.util.ArrayList;
import java.util.Arrays;
import java.util.List;

public class Solution {

    private static final int GRID_SIZE = 4;
    private static final int DIGIT_LENGTH = 16;

    /**
     * Counts numbers X <= N_str such that the digits at specific path indices match the required values V.
     * @param N_str The upper bound N as a 16-digit string (padded).
     * @param P The list of 7 path indices.
     * @param V The required non-decreasing sequence of 7 target digits.
     * @return The count of numbers satisfying the constraints.
     */
    private static long countLe(String N_str, int[] P, int[] V) {
        int[] N_digits = new int[DIGIT_LENGTH];
        for (int i = 0; i < DIGIT_LENGTH; i++) {
            N_digits[i] = N_str.charAt(i) - '0';
        }

        // Memoization table: dp[i][tight]
        // Since we are counting, the return type is long.
        long[][] memo = new long[DIGIT_LENGTH][2];
        for (int i = 0; i < DIGIT_LENGTH; i++) {
            Arrays.fill(memo[i], -1);
        }

        // DP function: returns the count of valid suffixes starting from index i
        java.util.function.BiFunction<Integer, Integer, Long> dp = new java.util.function.BiFunction<Integer, Integer, Long>() {
            @Override
            public Long apply(Integer i, Integer tight) {
                if (i == DIGIT_LENGTH) {
                    return 1L; // Found one valid number
                }
                if (memo[i][tight] != -1) {
                    return memo[i][tight];
                }

                long count = 0;
                int limit = (tight == 1) ? N_digits[i] : 9;

                for (int d = 0; d <= limit; d++) {
                    // Check constraint: If i is a path index P_k, d must match V[k].
                    boolean constraintOk = true;
                    for (int k = 0; k < 7; k++) {
                        if (P[k] == i) {
                            if (d != V[k]) {
                                constraintOk = false;
                                break;
                            }
                        }
                    }

                    if (constraintOk) {
                        int newTight = tight & (d == limit) ? 1 : 0;
                        count += apply(i + 1, newTight);
                    }
                }

                memo[i][tight] = count;
                return count;
            }
        };

        // Start DP from index 0, tight constraint active (1)
        return dp.apply(0, 1);
    }

    public static long solve(long l, long r, String directions) {
        // --- Step 1: Calculate Path Indices P_k ---
        int[] P = new int[7];
        int r_curr = 0;
        int c_curr = 0;

        // P[0] corresponds to (0, 0)
        P[0] = r_curr * GRID_SIZE + c_curr;

        for (int k = 0; k < 6; k++) {
            if (directions.charAt(k) == 'D') {
                r_curr += 1;
            } else { // 'R'
                c_curr += 1;
            }

            // Clamping as seen in reference solution
            r_curr = Math.min(r_curr, GRID_SIZE - 1);
            c_curr = Math.min(c_curr, GRID_SIZE - 1);

            P[k + 1] = r_curr * GRID_SIZE + c_curr;
        }

        // --- Step 2: Generate Valid Sequences V (v0 <= v1 <= ... <= v6) ---
        List<int[]> validVSequences = new ArrayList<>();

        // Recursive helper to generate sequences
        java.util.function.BiConsumer<Integer, int[], Integer> generateSequences = new java.util.function.BiConsumer<Integer, int[], Integer>() {
            @Override
            public void accept(Integer k, int[] currentV, Integer minVal) {
                if (k == 7) {
                    // Deep copy the sequence
                    int[] sequenceCopy = Arrays.copyOf(currentV, 7);
                    validVSequences.add(sequenceCopy);
                    return;
                }

                for (int v = minVal; v <= 9; v++) {
                    currentV[k] = v;
                    accept(k + 1, currentV, v);
                }
            }
        };

        int[] currentV = new int[7];
        generateSequences.accept(0, currentV, 0);


        // --- Step 3 & 4: Sum up differences ---
        long totalGoodNumbers = 0;

        // Calculate L-1
        long lMinus1 = l - 1;

        // Helper function to pad long to 16 digits string
        java.util.function.Function<Long, String> padTo16 = (n) -> {
            String s = String.valueOf(n);
            return String.format("%16s", s).replace(' ', '0');
        };


        for (int[] V : validVSequences) {
            // Count for R
            String R_str = padTo16.apply(r);
            long countR = countLe(R_str, P, V);

            // Count for L-1
